-- BRK-10O Borrower Communications
CREATE TABLE IF NOT EXISTS public.brokerage_borrower_message_templates (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), trigger_key text NOT NULL UNIQUE, channel text NOT NULL DEFAULT 'email' CHECK (channel IN ('email','sms','in_portal')), subject text, body_md text NOT NULL, active boolean NOT NULL DEFAULT true, version text NOT NULL DEFAULT 'v1', created_at timestamptz NOT NULL DEFAULT now());
ALTER TABLE public.brokerage_borrower_message_templates ENABLE ROW LEVEL SECURITY;
CREATE TABLE IF NOT EXISTS public.brokerage_borrower_message_outbox (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), deal_id uuid NOT NULL REFERENCES public.deals(id), trigger_key text NOT NULL, channel text NOT NULL CHECK (channel IN ('email','sms','in_portal')), recipient text, subject text, body text NOT NULL, status text NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','sent','failed','suppressed')), attempts integer NOT NULL DEFAULT 0, last_attempt_at timestamptz, sent_at timestamptz, error text, cooldown_key text, metadata jsonb NOT NULL DEFAULT '{}'::jsonb, created_at timestamptz NOT NULL DEFAULT now());
CREATE INDEX IF NOT EXISTS brk_borrower_outbox_cooldown_idx ON public.brokerage_borrower_message_outbox (cooldown_key, created_at DESC);
ALTER TABLE public.brokerage_borrower_message_outbox ENABLE ROW LEVEL SECURITY;
INSERT INTO public.brokerage_borrower_message_templates (trigger_key, channel, subject, body_md) VALUES ('session_started','in_portal','Welcome','Welcome! Buddy is ready to help build your SBA package.'),('uploads_needed','in_portal',NULL,'Buddy needs documents to verify your application.'),('disclosure_ack_needed','in_portal',NULL,'Please review and acknowledge disclosures. Buddy does not guarantee loan approval.'),('package_sealed','email','Package sealed','Your SBA package has been sealed and is visible to matched lenders.'),('lender_claim_received','in_portal',NULL,'A qualified SBA lender has expressed interest in your deal.'),('borrower_pick_needed','email','Choose your lender','Lenders have claimed your deal. Visit your portal to select one.'),('lender_selected','email','Lender selected','Your full package is being released to your selected lender.'),('condition_opened','in_portal',NULL,'A new closing condition has been added.'),('clear_to_close','email','Clear to close','All conditions satisfied. Your deal is clear to close.'),('funded','email','Loan funded','Congratulations! Your SBA loan has been funded.') ON CONFLICT (trigger_key) DO NOTHING;
